using ICSharpCode.WpfDesign;namespace BgCommon.UI.Designer.Preview{    /// <summary>    /// 预览服务    /// </summary>    public class PreviewService    {        private readonly PreviewManager _previewManager;                /// <summary>        /// 预览管理器        /// </summary>        public PreviewManager PreviewManager => _previewManager;                /// <summary>        /// 构造函数        /// </summary>        /// <param name="context">设计上下文</param>        public PreviewService(DesignContext context)        {            _previewManager = new PreviewManager(context);        }    }}